  #[allow(clippy::clone_on_copy)]
  #[allow(clippy::vec_init_then_push)]
  pub fn invoke_signed(&self, signers_seeds: &[&[&[u8]]]) -> solana_program::entrypoint::ProgramResult {
          let args = CreateWithdrawalWindowInstructionArgs {
                                                              start_time: self.instruction.start_time.clone().expect("start_time is not set"),
                                                                  end_time: self.instruction.end_time.clone().expect("end_time is not set"),
                                                                  earliest_withdrawal_time: self.instruction.earliest_withdrawal_time.clone().expect("earliest_withdrawal_time is not set"),
                                                                  expiration_time: self.instruction.expiration_time.clone().expect("expiration_time is not set"),
                                                                  max_withdrawal_amount: self.instruction.max_withdrawal_amount.clone().expect("max_withdrawal_amount is not set"),
                                    };
        let instruction = CreateWithdrawalWindowCpi {
        __program: self.instruction.__program,
                  
          pair: self.instruction.pair.expect("pair is not set"),
                  
          authority: self.instruction.authority.expect("authority is not set"),
                  
          access_control: self.instruction.access_control.expect("access_control is not set"),
                  
          withdrawal_window: self.instruction.withdrawal_window.expect("withdrawal_window is not set"),
                  
          base_token_mint: self.instruction.base_token_mint.expect("base_token_mint is not set"),
                  
          lst_mint: self.instruction.lst_mint.expect("lst_mint is not set"),
                  
          window_base_token_account: self.instruction.window_base_token_account.expect("window_base_token_account is not set"),
                  
          window_lst_account: self.instruction.window_lst_account.expect("window_lst_account is not set"),
                  
          token_program: self.instruction.token_program.expect("token_program is not set"),
                  
          associated_token_program: self.instruction.associated_token_program.expect("associated_token_program is not set"),
                  
          rent: self.instruction.rent.expect("rent is not set"),
                  
          system_program: self.instruction.system_program.expect("system_program is not set"),
                          __args: args,
            };
    instruction.invoke_signed_with_remaining_accounts(signers_seeds, &self.instruction.__remaining_accounts)
  }
